const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

// Configuration
const cosmosEndpoint = process.env.COSMOS_DB_ENDPOINT;
const cosmosKey = process.env.COSMOS_DB_KEY;
const databaseId = process.env.COSMOS_DB_DATABASE || 'BatchProcessingDB';
const sourceContainerId = process.env.COSMOS_DB_SOURCE_CONTAINER || 'SourceData';
const resultContainerId = process.env.COSMOS_DB_RESULT_CONTAINER || 'ProcessedData';
const checkpointContainerId = process.env.COSMOS_DB_CHECKPOINT_CONTAINER || 'Checkpoints';

const BATCH_SIZE = parseInt(process.env.BATCH_SIZE) || 500;
const MAX_RETRIES = parseInt(process.env.MAX_RETRIES) || 3;
const RETRY_DELAY_MS = parseInt(process.env.RETRY_DELAY_MS) || 1000;
const PROCESSING_TIMEOUT_MS = 9 * 60 * 1000; // 9 minutes safety margin (max is 10 min)

// Initialize Cosmos DB client with connection pooling and optimized settings
const cosmosClient = new CosmosClient({
    endpoint: cosmosEndpoint,
    key: cosmosKey,
    connectionPolicy: {
        requestTimeout: 60000,
        retryOptions: {
            maxRetryAttemptCount: 9,
            fixedRetryIntervalInMilliseconds: 0,
            maxWaitTimeInSeconds: 30
        },
        enableEndpointDiscovery: true,
        preferredLocations: []
    }
});

class BatchProcessor {
    constructor(context) {
        this.context = context;
        this.database = cosmosClient.database(databaseId);
        this.sourceContainer = this.database.container(sourceContainerId);
        this.resultContainer = this.database.container(resultContainerId);
        this.checkpointContainer = this.database.container(checkpointContainerId);
        this.processedCount = 0;
        this.errorCount = 0;
        this.startTime = Date.now();
        this.isTimedOut = false;
    }

    getRemainingTime() {
        return PROCESSING_TIMEOUT_MS - (Date.now() - this.startTime);
    }

    checkTimeRemaining() {
        const remaining = this.getRemainingTime();
        if (remaining <= 30000) { // 30 seconds safety buffer
            this.isTimedOut = true;
            this.context.log(`[WARNING] Approaching timeout. Remaining: ${remaining}ms. Initiating graceful shutdown.`);
            return false;
        }
        return true;
    }

    async loadCheckpoint(jobId) {
        try {
            const { resource } = await this.checkpointContainer.item(jobId, jobId).read();
            if (resource) {
                this.context.log(`Resuming from checkpoint: ${JSON.stringify(resource)}`);
                return resource;
            }
        } catch (error) {
            if (error.code !== 404) {
                this.context.log(`Error loading checkpoint: ${error.message}`);
            }
        }
        return {
            id: jobId,
            jobId: jobId,
            continuationToken: null,
            processedCount: 0,
            errorCount: 0,
            status: 'in_progress',
            lastUpdated: new Date().toISOString(),
            startedAt: new Date().toISOString()
        };
    }

    async saveCheckpoint(checkpoint) {
        try {
            checkpoint.lastUpdated = new Date().toISOString();
            checkpoint.processedCount = this.processedCount;
            checkpoint.errorCount = this.errorCount;
            await this.checkpointContainer.items.upsert(checkpoint);
            this.context.log(`Checkpoint saved. Processed: ${this.processedCount}, Errors: ${this.errorCount}`);
        } catch (error) {
            this.context.log(`[ERROR] Failed to save checkpoint: ${error.message}`);
        }
    }

    async retryWithBackoff(operation, operationName, retries = MAX_RETRIES) {
        for (let attempt = 1; attempt <= retries; attempt++) {
            try {
                return await operation();
            } catch (error) {
                const isRetryable = error.code === 429 || // Too Many Requests
                    error.code === 503 || // Service Unavailable
                    error.code === 408 || // Request Timeout
                    error.code === 'ECONNRESET' ||
                    error.code === 'ETIMEDOUT';

                if (!isRetryable || attempt === retries) {
                    this.context.log(`[ERROR] ${operationName} failed after ${attempt} attempts: ${error.message}`);
                    throw error;
                }

                const retryAfterMs = error.retryAfterInMs || 
                    (error.headers && error.headers['x-ms-retry-after-ms']) ||
                    RETRY_DELAY_MS * Math.pow(2, attempt - 1);

                this.context.log(`[RETRY] ${operationName} attempt ${attempt}/${retries}. Retrying after ${retryAfterMs}ms. Error: ${error.message}`);
                await this.delay(retryAfterMs);
            }
        }
    }

    delay(ms) {
        return new Promise(resolve => setTimeout(resolve, ms));
    }

    async processItem(item) {
        // Simulate complex data transformation/processing
        const processedItem = {
            id: `processed_${item.id}`,
            originalId: item.id,
            partitionKey: item.partitionKey || item.id,
            processedAt: new Date().toISOString(),
            data: {},
            metadata: {
                sourceContainer: sourceContainerId,
                processingVersion: '1.0.0'
            }
        };

        // Apply business logic transformations
        if (item.data) {
            processedItem.data = this.transformData(item.data);
        }

        // Data validation
        if (!this.validateProcessedItem(processedItem)) {
            throw new Error(`Validation failed for item ${item.id}`);
        }

        return processedItem;
    }

    transformData(data) {
        // Example transformation logic - customize per your needs
        const transformed = { ...data };

        // Normalize string fields
        for (const [key, value] of Object.entries(transformed)) {
            if (typeof value === 'string') {
                transformed[key] = value.trim();
            }
            if (typeof value === 'number') {
                transformed[`${key}_normalized`] = Math.round(value * 100) / 100;
            }
        }

        transformed._transformedAt = new Date().toISOString();
        return transformed;
    }

    validateProcessedItem(item) {
        return item && item.id && item.originalId;
    }

    async writeBatchToCosmosDB(items) {
        const results = { succeeded: 0, failed: 0, errors: [] };

        // Use bulk operations for better throughput
        const operations = items.map(item => ({
            operationType: 'Upsert',
            resourceBody: item,
            partitionKey: item.partitionKey || item.id
        }));

        // Process in sub-batches to avoid exceeding bulk operation limits
        const SUB_BATCH_SIZE = 100;
        for (let i = 0; i < operations.length; i += SUB_BATCH_SIZE) {
            if (!this.checkTimeRemaining()) break;

            const subBatch = operations.slice(i, i + SUB_BATCH_SIZE);

            try {
                const bulkResult = await this.retryWithBackoff(
                    () => this.resultContainer.items.bulk(subBatch),
                    `Bulk write (batch offset ${i})`
                );

                for (const result of bulkResult) {
                    if (result.statusCode >= 200 && result.statusCode < 300) {
                        results.succeeded++;
                    } else {
                        results.failed++;
                        results.errors.push({
                            statusCode: result.statusCode,
                            itemId: result.resourceBody?.id
                        });
                    }
                }
            } catch (error) {
                // Fallback: write items individually
                this.context.log(`Bulk write failed, falling back to individual writes: ${error.message}`);
                for (const op of subBatch) {
                    try {
                        await this.retryWithBackoff(
                            () => this.resultContainer.items.upsert(op.resourceBody),
                            `Individual write ${op.resourceBody.id}`
                        );
                        results.succeeded++;
                    } catch (individualError) {
                        results.failed++;
                        results.errors.push({
                            error: individualError.message,
                            itemId: op.resourceBody?.id
                        });
                    }
                }
            }
        }

        return results;
    }

    async fetchBatch(query, continuationToken) {
        const queryOptions = {
            maxItemCount: BATCH_SIZE,
            continuationToken: continuationToken || undefined,
            bufferItems: true,
            maxDegreeOfParallelism: 4
        };

        const response = await this.retryWithBackoff(
            async () => {
                const iterator = this.sourceContainer.items.query(query, queryOptions);
                return await iterator.fetchNext();
            },
            'Fetch batch'
        );

        return {
            items: response.resources || [],
            continuationToken: response.continuationToken,
            requestCharge: response.requestCharge
        };
    }

    async run(jobId, query) {
        this.context.log(`Starting batch processing job: ${jobId}`);
        this.context.log(`Query: ${query}`);
        this.context.log(`Batch size: ${BATCH_SIZE}`);
        this.context.log(`Max processing time: ${PROCESSING_TIMEOUT_MS}ms`);

        const checkpoint = await this.loadCheckpoint(jobId);
        this.processedCount = checkpoint.processedCount || 0;
        this.errorCount = checkpoint.errorCount || 0;

        let continuationToken = checkpoint.continuationToken;
        let batchNumber = 0;
        let totalRequestCharge = 0;
        let hasMoreResults = true;

        try {
            while (hasMoreResults && !this.isTimedOut) {
                if (!this.checkTimeRemaining()) {
                    this.context.log('Time limit approaching. Saving progress and exiting gracefully.');
                    break;
                }

                batchNumber++;
                this.context.log(`Processing batch #${batchNumber}...`);

                // Fetch batch from Cosmos DB
                const fetchResult = await this.fetchBatch(query, continuationToken);
                const { items, requestCharge } = fetchResult;
                continuationToken = fetchResult.continuationToken;
                totalRequestCharge += requestCharge || 0;

                if (!items || items.length === 0) {
                    this.context.log('No more items to process.');
                    hasMoreResults = false;
                    break;
                }

                this.context.log(`Fetched ${items.length} items (RU charge: ${requestCharge})`);

                // Process items in parallel with concurrency control
                const CONCURRENCY_LIMIT = 10;
                const processedItems = [];
                const processingErrors = [];

                for (let i = 0; i < items.length; i += CONCURRENCY_LIMIT) {
                    if (!this.checkTimeRemaining()) break;

                    const chunk = items.slice(i, i + CONCURRENCY_LIMIT);
                    const chunkResults = await Promise.allSettled(
                        chunk.map(item => this.processItem(item))
                    );

                    for (let j = 0; j < chunkResults.length; j++) {
                        const result = chunkResults[j];
                        if (result.status === 'fulfilled') {
                            processedItems.push(result.value);
                        } else {
                            this.errorCount++;
                            processingErrors.push({
                                itemId: chunk[j]?.id,
                                error: result.reason?.message
                            });
                        }
                    }
                }

                // Write processed items to destination container
                if (processedItems.length > 0) {
                    const writeResult = await this.writeBatchToCosmosDB(processedItems);
                    this.processedCount += writeResult.succeeded;
                    this.errorCount += writeResult.failed;

                    this.context.log(
                        `Batch #${batchNumber} complete. Written: ${writeResult.succeeded}, ` +
                        `Failed: ${writeResult.failed}, Processing errors: ${processingErrors.length}`
                    );

                    if (writeResult.errors.length > 0) {
                        this.context.log(`Write errors: ${JSON.stringify(writeResult.errors.slice(0, 5))}`);
                    }
                }

                if (processingErrors.length > 0) {
                    this.context.log(`Processing errors: ${JSON.stringify(processingErrors.slice(0, 5))}`);
                }

                // Save checkpoint after each batch
                checkpoint.continuationToken = continuationToken;
                checkpoint.lastBatchNumber = batchNumber;
                await this.saveCheckpoint(checkpoint);

                // Check if there are more results
                if (!continuationToken) {
                    hasMoreResults = false;
                    this.context.log('All items have been processed (no continuation token).');
                }
            }

            // Final checkpoint update
            const isComplete = !hasMoreResults && !this.isTimedOut;
            checkpoint.status = isComplete ? 'completed' : 'paused';
            checkpoint.continuationToken = continuationToken;
            checkpoint.completedAt = isComplete ? new Date().toISOString() : undefined;
            await this.saveCheckpoint(checkpoint);

            const elapsedMs = Date.now() - this.startTime;
            const summary = {
                jobId,
                status: checkpoint.status,
                totalProcessed: this.processedCount,
                totalErrors: this.errorCount,
                batchesProcessed: batchNumber,
                totalRequestCharge: Math.round(totalRequestCharge * 100) / 100,
                elapsedMs,
                elapsedFormatted: `${Math.floor(elapsedMs / 60000)}m ${Math.floor((elapsedMs % 60000) / 1000)}s`,
                hasMoreData: !!continuationToken,
                timedOut: this.isTimedOut
            };

            this.context.log(`Job summary: ${JSON.stringify(summary)}`);
            return summary;

        } catch (error) {
            // Save checkpoint even on failure so we can resume
            checkpoint.status = 'failed';
            checkpoint.error = error.message;
            checkpoint.continuationToken = continuationToken;
            await this.saveCheckpoint(checkpoint);

            throw error;
        }
    }
}

