// HTTP-triggered function for on-demand batch processing
app.http('batchProcessorHttp', {
    methods: ['POST'],
    authLevel: 'function',
    handler: async (request, context) => {
        context.log('HTTP-triggered batch processor started.');

        let body;
        try {
            body = await request.json();
        } catch {
            body = {};
        }

        const jobId = body.jobId || `batch_manual_${Date.now()}`;
        const query = body.query || process.env.COSMOS_DB_QUERY || 'SELECT * FROM c WHERE NOT IS_DEFINED(c._processed) OR c._processed = false';
        const resetCheckpoint = body.resetCheckpoint || false;

        const processor = new BatchProcessor(context);

        // Reset checkpoint if requested
        if (resetCheckpoint) {
            try {
                await processor.checkpointContainer.item(jobId, jobId).delete();
                context.log(`Checkpoint for job ${jobId} has been reset.`);
            } catch (error) {
                if (error.code !== 404) {
                    context.log(`Warning: Could not reset checkpoint: ${error.message}`);
                }
            }
        }

        try {
            const result = await processor.run(jobId, query);
            return {
                status: 200,
                jsonBody: {
                    success: true,
                    ...result
                }
            };
        } catch (error) {
            context.log(`[FATAL] Batch processing job ${jobId} failed: ${error.message}`);
            return {
                status: 500,
                jsonBody: {
                    success: false,
                    jobId,
                    error: error.message,
                    processedBeforeFailure: processor.processedCount,
                    errorsBeforeFailure: processor.errorCount
                }
            };
        }
    }
});

// HTTP endpoint to check job status
app.http('batchProcessorStatus', {
    methods: ['GET'],
    authLevel: 'function',
    route: 'batch/status/{jobId}',
    handler: async (request, context) => {
        const jobId = request.params.jobId;

        if (!jobId) {
            return {
                status: 400,
                jsonBody: { error: 'jobId parameter is required' }
            };
        }

        try {
            const database = cosmosClient.database(databaseId);
            const checkpointContainer = database.container(checkpointContainerId);
            const { resource: checkpoint } = await checkpointContainer.item(jobId, jobId).read();

            if (!checkpoint) {
                return {
                    status: 404,
                    jsonBody: { error: `Job ${jobId} not found` }
                };
            }

            return {
                status: 200,
                jsonBody: {
                    jobId: checkpoint.jobId,
                    status: checkpoint.status,
                    processedCount: checkpoint.processedCount,
                    errorCount: checkpoint.errorCount,
                    lastBatchNumber: checkpoint.lastBatchNumber,
                    startedAt: checkpoint.startedAt,
                    lastUpdated: checkpoint.lastUpdated,
                    completedAt: checkpoint.completedAt,
                    hasMoreData: !!checkpoint.continuationToken,
                    error: checkpoint.error
                }
            };
        } catch (error) {
            if (error.code === 404) {
                return {
                    status: 404,
                    jsonBody: { error: `Job ${jobId} not found` }
                };
            }
            return {
                status: 500,
                jsonBody: { error: error.message }
            };
        }
    }
});

